func TestUintJSON(t *testing.T) {
	assert := require.New(t)

	type S struct {
		A Uint
		B [3]Uint
		C *Uint
		D *Uint
	}

	// encode to JSON
	var s S
	s.A.SetString("-1")
	s.B[2].SetUint64(42)
	s.D = new(Uint).SetUint64(8000)

	encoded, err := json.Marshal(&s)
	assert.NoError(err)
	// we may need to adjust "42" and "8000" values for some moduli; see Text() method for more details.
	formatValue := func(v int64) string {
		var a big.Int
		a.SetInt64(v)
		a.Mod(&a, Modulus())
		const maxUint16 = 65535
		var aNeg big.Int
		aNeg.Neg(&a).Mod(&aNeg, Modulus())
		if aNeg.Uint64() != 0 && aNeg.Uint64() <= maxUint16 {
			return "-" + aNeg.Text(10)
		}
		return a.Text(10)
	}
	expected := fmt.Sprintf("{\"A\":%s,\"B\":[0,0,%s],\"C\":null,\"D\":%s}", formatValue(-1), formatValue(42), formatValue(8000))
	assert.Equal(expected, string(encoded))

	// decode valid
	var decoded S
	err = json.Unmarshal([]byte(expected), &decoded)
	assert.NoError(err)

	assert.Equal(s, decoded, "element -> json -> element round trip failed")

	// decode hex and string values
	withHexValues := "{\"A\":\"-1\",\"B\":[0,\"0x00000\",\"0x2A\"],\"C\":null,\"D\":\"8000\"}"

	var decodedS S
	err = json.Unmarshal([]byte(withHexValues), &decodedS)
	assert.NoError(err)

	assert.Equal(s, decodedS, " json with strings  -> element  failed")

}

type testPairUint struct {
	element Uint
	bigint  big.Int
}

func gen() gopter.Gen {
	return func(genParams *gopter.GenParameters) *gopter.GenResult {
		var g testPairUint

		g.element = Uint{
			genParams.NextUint64(),
			genParams.NextUint64(),
		}
		if qElement[1] != ^uint64(0) {
			g.element[1] %= (qElement[1] + 1)
		}

		for !g.element.smallerThanModulus() {
			g.element = Uint{
				genParams.NextUint64(),
				genParams.NextUint64(),
			}
			if qElement[1] != ^uint64(0) {
				g.element[1] %= (qElement[1] + 1)
			}
		}

		g.element.BigInt(&g.bigint)
		genResult := gopter.NewGenResult(g, gopter.NoShrinker)
		return genResult
	}
}

func genRandomFq(genParams *gopter.GenParameters) Uint {
	var g Uint

	g = Uint{
		genParams.NextUint64(),
		genParams.NextUint64(),
	}

	if qElement[1] != ^uint64(0) {
		g[1] %= (qElement[1] + 1)
	}

	for !g.smallerThanModulus() {
		g = Uint{
			genParams.NextUint64(),
			genParams.NextUint64(),
		}
		if qElement[1] != ^uint64(0) {
			g[1] %= (qElement[1] + 1)
		}
	}

	return g
}

func genFull() gopter.Gen {
	return func(genParams *gopter.GenParameters) *gopter.GenResult {
		a := genRandomFq(genParams)

		var carry uint64
		a[0], carry = bits.Add64(a[0], qElement[0], carry)
		a[1], _ = bits.Add64(a[1], qElement[1], carry)

		genResult := gopter.NewGenResult(a, gopter.NoShrinker)
		return genResult
	}
}

func genUint() gopter.Gen {
	return func(genParams *gopter.GenParameters) *gopter.GenResult {
		a := genRandomFq(genParams)
		genResult := gopter.NewGenResult(a, gopter.NoShrinker)
		return genResult
	}
}
